import{_ as a,a as t,b as o,c as r}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as d,o as c,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Adicionar canal compatível com S3","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/upload/s3.md","filePath":"pt-BR/upload/s3.md","lastUpdated":1781962217000}'),n={name:"pt-BR/upload/s3.md"};function l(p,e,m,h,u,b){return c(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="adicionar-canal-compativel-com-s3" tabindex="-1">Adicionar canal compatível com S3 <a class="header-anchor" href="#adicionar-canal-compativel-com-s3" aria-label="Permalink to &quot;Adicionar canal compatível com S3&quot;">​</a></h1><p>O canal S3 permite usar armazenamento de objetos compatível com a API S3.</p><p>Serve para Cloudflare R2, Backblaze B2, MinIO, AWS S3 e outros serviços compatíveis.</p><h2 id="o-que-preparar" tabindex="-1">O que preparar <a class="header-anchor" href="#o-que-preparar" aria-label="Permalink to &quot;O que preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Uso</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>URL da API do armazenamento</td></tr><tr><td>Bucket</td><td>Bucket onde os arquivos serão salvos</td></tr><tr><td>Region</td><td>Região do armazenamento; no Cloudflare R2 costuma ser <code>auto</code></td></tr><tr><td>Access Key ID</td><td>Chave de acesso</td></tr><tr><td>Secret Access Key</td><td>Chave secreta</td></tr><tr><td>Domínio CDN</td><td>Opcional, para URLs públicas personalizadas</td></tr></tbody></table><p>Exemplo com Cloudflare R2 pela API S3:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://seuAccountID.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: nome-do-bucket</span></span>
<span class="line"><span>Region: auto</span></span></code></pre></div><h2 id="onde-adicionar" tabindex="-1">Onde adicionar <a class="header-anchor" href="#onde-adicionar" aria-label="Permalink to &quot;Onde adicionar&quot;">​</a></h2><ol><li>Abra Configurações do sistema.</li><li>Entre em Configurações de upload.</li><li>Clique em <code>Adicionar canal</code>.</li><li>Escolha <code>S3</code>.</li></ol><h2 id="campos" tabindex="-1">Campos <a class="header-anchor" href="#campos" aria-label="Permalink to &quot;Campos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Descrição</th></tr></thead><tbody><tr><td>Nome do canal</td><td>Por exemplo <code>R2-S3</code> ou <code>MinIO</code></td></tr><tr><td>Endpoint</td><td>URL S3 completa com <code>https://</code></td></tr><tr><td>Domínio CDN personalizado</td><td>Opcional; usado ao gerar links</td></tr><tr><td>Bucket</td><td>Nome do bucket</td></tr><tr><td>Region</td><td><code>auto</code> para R2; outros provedores conforme documentação</td></tr><tr><td>Access Key ID</td><td>Chave de acesso</td></tr><tr><td>Secret Access Key</td><td>Chave secreta</td></tr><tr><td>Path-style access</td><td>Apenas se o provedor exigir</td></tr><tr><td>Limite de capacidade</td><td>Opcional</td></tr></tbody></table><h2 id="criar-chaves-s3-para-r2" tabindex="-1">Criar chaves S3 para R2 <a class="header-anchor" href="#criar-chaves-s3-para-r2" aria-label="Permalink to &quot;Criar chaves S3 para R2&quot;">​</a></h2><p>No Cloudflare Dashboard, abra <code>R2 Object Storage</code> e entre no gerenciamento de API Tokens.</p><p>![Entrada R2 API Token](../../image/upload/s3/r2 api token入口.png)</p><p>Crie um token R2 com acesso ao bucket alvo.</p><p><img src="`+a+'" alt="Criar API Token" loading="lazy"></p><p>Copie <code>Access Key ID</code> e <code>Secret Access Key</code>.</p><p><img src="'+t+'" alt="Copiar valores" loading="lazy"></p><h2 id="preencher-no-imgbed" tabindex="-1">Preencher no ImgBed <a class="header-anchor" href="#preencher-no-imgbed" aria-label="Permalink to &quot;Preencher no ImgBed&quot;">​</a></h2><ol><li>Informe <code>Endpoint</code>, <code>Bucket</code> e <code>Region</code>.</li><li>Informe Access Key ID e Secret Access Key.</li><li>Se usar CDN, preencha o domínio personalizado.</li><li>Ative Path-style access apenas se o serviço exigir.</li><li>Salve.</li></ol><p><img src="'+o+'" alt="Configuração S3" loading="lazy"></p><h2 id="verificacao" tabindex="-1">Verificação <a class="header-anchor" href="#verificacao" aria-label="Permalink to &quot;Verificação&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ponto</th><th>Estado esperado</th></tr></thead><tbody><tr><td>Cartão do canal</td><td>Aparece depois de salvar</td></tr><tr><td>Upload de teste</td><td>Cria objeto no bucket</td></tr><tr><td>Link</td><td>A URL retornada pelo ImgBed abre corretamente</td></tr><tr><td>Capacidade</td><td>Se houver limite, mostra uso</td></tr></tbody></table><p><img src="'+r+'" alt="Capacidade S3" loading="lazy"></p><p>A estatística de capacidade S3 é calculada pelos registros locais do ImgBed no D1, não por varredura em tempo real do bucket.</p><h2 id="erros-comuns" tabindex="-1">Erros comuns <a class="header-anchor" href="#erros-comuns" aria-label="Permalink to &quot;Erros comuns&quot;">​</a></h2><ul><li>Endpoint sem <code>https://</code>.</li><li>Bucket ou Region incorretos.</li><li>Access Key sem permissão de escrita.</li><li>Provedor exige Path-style access.</li><li>CDN não conectado corretamente ao bucket.</li></ul>',27)])])}const C=d(n,[["render",l]]);export{k as __pageData,C as default};
